import io
import logging
import os
import re
import shutil
import sys
import tempfile
from collections import OrderedDict
from contextlib import contextmanager
from typing import (IO, Dict, Iterable, Iterator, Mapping, Optional, Tuple,
                    Union)

from .parser import Binding, parse_stream
from .variables import parse_variables

# A type alias for a string path to be used for the paths in this file.
# These paths may flow to `open()` and `shutil.move()`; `shutil.move()`
# only accepts string paths, not byte paths or file descriptors. See
# https://github.com/python/typeshed/pull/6832.
StrPath = Union[str, 'os.PathLike[str]']

logger = logging.getLogger(__name__)


def with_warn_for_invalid_lines(mappings: Iterator[Binding]) -> Iterator[Binding]:
    """Yield bindings and warn when a binding contains a parse error.

    This helper wraps an iterator of Binding objects produced by the parser
    and logs a warning for any binding that had a parse error, but still
    yields the binding so that further processing can continue.
    """
    for mapping in mappings:
        if mapping.error:
            logger.warning(
                "Python-dotenv could not parse statement starting at line %s",
                mapping.original.line,
            )
        yield mapping


class DotEnv:
    def __init__(
        self,
        dotenv_path: Optional[StrPath],
        stream: Optional[IO[str]] = None,
        verbose: bool = False,
        encoding: Optional[str] = None,
        interpolate: bool = True,
        override: bool = True,
    ) -> None:
        """Create a DotEnv instance.

        Args:
            dotenv_path: Path to a .env file. If None, a provided stream can
                be used instead.
            stream: Optional text stream to read dotenv content from. If both
                stream and dotenv_path are provided and the path exists, the
                file at dotenv_path takes precedence.
            verbose: If True, log informational messages about missing files
                or keys.
            encoding: Encoding used to open the dotenv file.
            interpolate: Whether to resolve ${VAR} style references between
                variables when building the mapping.
            override: Whether variables defined in the dotenv should override
                existing environment variables when interpolating.
        """
        self.dotenv_path: Optional[StrPath] = dotenv_path
        self.stream: Optional[IO[str]] = stream
        self._dict: Optional[Dict[str, Optional[str]]] = None
        self.verbose: bool = verbose
        self.encoding: Optional[str] = encoding
        self.interpolate: bool = interpolate
        self.override: bool = override

    @contextmanager
    def _get_stream(self) -> Iterator[IO[str]]:
        """Context manager that yields a readable text stream for the dotenv.

        If a dotenv_path is provided and points to an existing file, that file
        will be opened and yielded. Otherwise, if a stream was provided at
        construction it will be yielded. If neither is available, an empty
        StringIO is yielded and an informational message is logged when
        verbose=True.
        """
        if self.dotenv_path and os.path.isfile(self.dotenv_path):
            with open(self.dotenv_path, encoding=self.encoding) as stream:
                yield stream
        elif self.stream is not None:
            yield self.stream
        else:
            if self.verbose:
                logger.info(
                    "Python-dotenv could not find configuration file %s.",
                    self.dotenv_path or '.env',
                )
            yield io.StringIO('')

    def dict(self) -> Dict[str, Optional[str]]:
        """Return dotenv as dict"""
        if self._dict:
            return self._dict

        raw_values = self.parse()

        if self.interpolate:
            self._dict = OrderedDict(resolve_variables(raw_values, override=self.override))
        else:
            self._dict = OrderedDict(raw_values)

        return self._dict

    def parse(self) -> Iterator[Tuple[str, Optional[str]]]:
        """Parse the dotenv stream and yield (key, value) pairs.

        This reads from the configured stream or file and yields keys and
        their corresponding (possibly None) values as returned by the
        underlying parser.
        """
        with self._get_stream() as stream:
            for mapping in with_warn_for_invalid_lines(parse_stream(stream)):
                if mapping.key is not None:
                    yield mapping.key, mapping.value

    def set_as_environment_variables(self) -> bool:
        """
        Load the current dotenv as system environment variable.
        """
        if not self.dict():
            return False

        for k, v in self.dict().items():
            if k in os.environ and not self.override:
                continue
            if v is not None:
                os.environ[k] = v

        return True

    def get(self, key: str) -> Optional[str]:
        """
        """
        data = self.dict()

        if key in data:
            return data[key]

        if self.verbose:
            logger.warning("Key %s not found in %s.", key, self.dotenv_path)

        return None


def get_key(
    dotenv_path: StrPath,
    key_to_get: str,
    encoding: Optional[str] = "utf-8",
) -> Optional[str]:
    """
    Get the value of a given key from the given .env.

    Returns `None` if the key isn't found or doesn't have a value.
    """
    return DotEnv(dotenv_path, verbose=True, encoding=encoding).get(key_to_get)


@contextmanager
def rewrite(
    path: StrPath,
    encoding: Optional[str],
) -> Iterator[Tuple[IO[str], IO[str]]]:
    """Context manager to safely rewrite a file.

    Yields a tuple (source_stream, dest_stream) where source_stream is an
    open readable stream for the existing file contents (or an empty
    StringIO if the file does not exist) and dest_stream is an open writable
    temporary file that should be written with the new contents. On exit,
    the temporary file will atomically replace the original file.

    Args:
        path: The path to the file that will be rewritten.
        encoding: Optional encoding for reading/writing the file.
    """
    source_stream: IO[str]
    if not os.path.isfile(path):
        source_stream = io.StringIO('')
    else:
        source_stream = open(path, encoding=encoding)

    dirpath = os.path.dirname(os.path.abspath(path)) or None
    fd, tmp_path = tempfile.mkstemp(dir=dirpath)
    os.close(fd)
    try:
        with open(tmp_path, 'w', encoding=encoding) as dest_stream:
            try:
                yield source_stream, dest_stream
            except Exception:
                # If an exception is raised in the with-block, remove the
                # temporary file and re-raise.
                try:
                    dest_stream.close()
                except Exception:
                    pass
                try:
                    os.remove(tmp_path)
                except Exception:
                    pass
                raise
    finally:
        # Ensure source stream is closed if it was a real file.
        try:
            if hasattr(source_stream, "close"):
                source_stream.close()
        except Exception:
            pass

    # Move temporary file to target location atomically.
    try:
        shutil.move(tmp_path, path)
    except Exception:
        # If move fails, try to remove the temporary file to avoid leaving
        # stray files behind, then re-raise.
        try:
            os.remove(tmp_path)
        except Exception:
            pass
        raise


def resolve_variables(
    mappings: Iterable[Tuple[str, Optional[str]]],
    override: bool = True,
) -> Dict[str, Optional[str]]:
    """Resolve variable references between mappings.

    Given an iterable of (key, value) pairs, resolve ${VAR} and $VAR style
    references in the values using previously defined variables in the same
    iterable and environment variables. The order of mappings is respected
    so that earlier definitions are available to later ones. If override is
    True, variables defined in the dotenv take precedence over environment
    variables for interpolation; otherwise, environment variables take
    precedence.

    Returns an ordered dict mapping keys to their resolved values (None
    values are preserved).
    """
    result: "OrderedDict[str, Optional[str]]" = OrderedDict()
    env = dict(os.environ)

    var_pattern = re.compile(r'\$(?:\{([^}]+)\}|([A-Za-z_][A-Za-z0-9_]*))')

    def lookup(var_name: str) -> str:
        # Check dotenv-defined variables first or environment first depending on override
        if override:
            if var_name in result and result[var_name] is not None:
                return result[var_name]  # type: ignore[return-value]
            return env.get(var_name, '')
        else:
            if var_name in env:
                return env[var_name]
            if var_name in result and result[var_name] is not None:
                return result[var_name]  # type: ignore[return-value]
            return ''

    for key, raw_value in mappings:
        if raw_value is None:
            result[key] = None
            continue

        def _replacer(match: re.Match) -> str:
            var_name = match.group(1) or match.group(2)
            return lookup(var_name)

        try:
            resolved = var_pattern.sub(_replacer, raw_value)
        except Exception:
            # In case of any unexpected error during substitution, fall back
            # to the original raw value.
            resolved = raw_value

        result[key] = resolved

    return result